{"file_text": "generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id        String   @id @default(uuid())
  email     String   @unique
  password  String
  role      String   @default("USER")
  createdAt DateTime @default(now())
}

model Restaurant {
  id        String   @id @default(uuid())
  name      String
  menuItems MenuItem[]
}

model MenuItem {
  id           String     @id @default(uuid())
  name         String
  price        Float
  restaurantId String
  restaurant   Restaurant @relation(fields: [restaurantId], references: [id])
}

model Order {
  id         String      @id @default(uuid())
  total      Float
  items      OrderItem[]
  createdAt  DateTime    @default(now())
}

model OrderItem {
  id         String   @id @default(uuid())
  orderId    String
  order      Order    @relation(fields: [orderId], references: [id])
  menuItemId String
}
